1	export function formatProbability(p: number): string {
2	  return `${(p * 100).toFixed(1)}%`;
3	}
4	
5	export function formatCurrency(n: number): string {
6	  if (Math.abs(n) >= 1_000_000) return `${(n / 1_000_000).toFixed(1)}M`;
7	  if (Math.abs(n) >= 1_000) return `${(n / 1_000).toFixed(1)}K`;
8	  return n.toFixed(2);
9	}
